import { useEffect, useImperativeHandle, useRef, useState } from "react";
import type { ITreeItem, TreeNode } from "@lmb/kitsconcerto-types";
import { buildTree } from "../../../../Organism/TreeView/utils";
import { useSelect } from "../SelectContext";

export interface TreeBuildProps {
    isStructured?: boolean;
    ref?: any;
}

/**
 * Shared hook for TreeSelect web & native.
 *
 * Manages: nodes state, value state, tree building from flat/structured data,
 * expandNode helper, and selectedValue sync.
 */
export const useTreeBuild = <T = any>(props: TreeBuildProps) => {
    const { isStructured, ref } = props;

    const { list, onChange, selectedValue } = useSelect();

    const [nodes, setNodes] = useState<TreeNode<ITreeItem<T>>[]>([]);
    const [value, setValue] = useState<any>(null);

    const nodesMapping = useRef<Map<string | number, ITreeItem<T>>>(new Map());

    useEffect(() => {
        if (selectedValue != null) {
            setValue(selectedValue);
        }
    }, [selectedValue]);

    const expandNode = (
        node: TreeNode,
        _expandedKeys: { [x: string]: boolean },
    ) => {
        if (node.children && node.children.length) {
            if (node.key) _expandedKeys[node.key] = true;
            for (const child of node.children) {
                expandNode(child, _expandedKeys);
            }
        }
    };

    const setNodesMapping = (newMap: Map<string | number, ITreeItem<T>>) => {
        nodesMapping.current = newMap;
        setNodes(buildTree(nodesMapping.current, true));
    };

    const build = () => {
        if (isStructured) {
            setNodes(list as TreeNode<ITreeItem<T>>[]);
            return;
        }
        const mapping = new Map(
            list.map((item) => [item.value.toString(), item]),
        );
        setNodesMapping(mapping);
    };

    useEffect(() => {
        build();
    }, [list]);

    useImperativeHandle(ref, () => ({}));

    const handleChange = (e: any) => {
        setValue(e.value);
        onChange && onChange(e);
    };

    return {
        nodes,
        value,
        setValue,
        expandNode,
        handleChange,
        list,
        onChange,
        selectedValue,
    };
};
